        fileChooserLauncher = registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
            val callback = filePathCallback
            if (callback == null) return@registerForActivityResult

            val results = mutableListOf<Uri>()

            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val clipData = data?.clipData
                val singleData = data?.data

                if (clipData != null) {
                    for (i in 0 until clipData.itemCount) {
                        clipData.getItemAt(i)?.uri?.let { results.add(it) }
                    }
                } else if (singleData != null) {
                    results.add(singleData)
                } else if (cameraImageUri != null) {
                    results.add(cameraImageUri!!)
                }
            }

            callback.onReceiveValue(if (results.isEmpty()) null else results.toTypedArray())
            filePathCallback = null
            cameraImageUri = null
        }

        cameraPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            val callbackId = pendingCameraCallbackId
            if (granted) {
                callbackId?.let { dispatchJsCallback(it, successPayload("granted", JSONObject())) }
            } else {
                callbackId?.let { dispatchJsCallback(it, errorPayload("CAMERA_PERMISSION_DENIED", "Camera permission denied")) }
            }
            pendingCameraCallbackId = null
        }

        notificationPermissionLauncher = registerForActivityResult(ActivityResultContracts.RequestPermission()) { granted ->
            val callbackId = pendingNotificationCallbackId
            if (granted) {
