    private fun handleExternalSchemes(uri: Uri): Boolean {
        val scheme = uri.scheme ?: return false
        return if (scheme !in listOf("http", "https", "file", "about", "javascript")) {
            startActivity(Intent(Intent.ACTION_VIEW, uri))
            true
        } else {
            false
        }
    }

    private fun createImageCaptureIntent(): Intent? {
        val imageFile = createImageFile(this) ?: return null
        cameraImageUri = FileProvider.getUriForFile(this, "${packageName}.fileprovider", imageFile)
        return Intent(MediaStore.ACTION_IMAGE_CAPTURE).apply {
            putExtra(MediaStore.EXTRA_OUTPUT, cameraImageUri)
            addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION)
            addFlags(Intent.FLAG_GRANT_WRITE_URI_PERMISSION)
        }
    }

    private fun dispatchJsCallback(callbackId: String, payload: JSONObject) {
        val escaped = JSONObject.quote(payload.toString())
        webView.post {
            webView.evaluateJavascript(
                "window.HybridNative && window.HybridNative.__resolve && window.HybridNative.__resolve('$callbackId', JSON.parse($escaped));",
                null
