class HybridBridge(
    private val activity: HybridWebViewActivity,
    private val webView: WebView
) {

    @JavascriptInterface
    fun requestCameraAccess(callbackId: String) {
        activity.runOnUiThread {
            activity.requestCameraPermission(callbackId)
