        val prefs = activity.getSharedPreferences("hybrid_local_storage", Context.MODE_PRIVATE)
        prefs.edit().putString(key, value).apply()
        callbackId?.takeIf { it.isNotBlank() }?.let {
            activity.runOnUiThread {
                activity.javaClass.getDeclaredMethod("dispatchJsCallback", String::class.java, JSONObject::class.java)
