                        put("success", true)
                        put("type", "localStorageSet")
                        put("data", JSONObject().apply {
                            put("key", key)
                        })
                    })
            }
        }
    }

    @JavascriptInterface
    fun getLocalStorageItem(key: String, callbackId: String) {
        val prefs = activity.getSharedPreferences("hybrid_local_storage", Context.MODE_PRIVATE)
        val value = prefs.getString(key, null)
        activity.runOnUiThread {
            val payload = JSONObject().apply {
                put("success", true)
                put("type", "localStorageGet")
                put("data", JSONObject().apply {
                    put("key", key)
