                null
            )
        }
    }

    @JavascriptInterface
    fun removeLocalStorageItem(key: String, callbackId: String?) {
        val prefs = activity.getSharedPreferences("hybrid_local_storage", Context.MODE_PRIVATE)
        prefs.edit().remove(key).apply()
        callbackId?.takeIf { it.isNotBlank() }?.let {
            activity.runOnUiThread {
                val payload = JSONObject().apply {
                    put("success", true)
                    put("type", "localStorageRemove")
                    put("data", JSONObject().apply {
                        put("key", key)
                    })
                }
                val escaped = JSONObject.quote(payload.toString())
                webView.evaluateJavascript(
                    "window.HybridNative && window.HybridNative.__resolve && window.HybridNative.__resolve('$callbackId', JSON.parse($escaped));",
                    null
